26-07-07 20:44:09','2026-07-07 20:44:09','',339,'https://overtakefan.s2-tastewp.com/?p=355',0,'revision','',0),(356,1,'2026-07-08 18:48:04','2026-07-08 18:48:04','<!-- wp:paragraph -->\n<p>[wpforms id=\"339\"]</p>\n<!-- /wp:paragraph -->','Adoption Form','','publish','closed','closed','','adoption-form','','','2026-07-08 19:36:40','2026-07-08 19:36:40','',0,'https://overtakefan.s2-tastewp.com/?page_id=356',0,'page','',0),(357,1,'2026-07-08 18:48:04','2026-07-08 18:48:04','<!-- wp:paragraph -->\n<p>[wpforms id=\"339\"]</p>\n<!-- /wp:paragraph -->','Adoption Form','','inherit','closed','closed','','356-revision-v1','','','2026-07-08 18:48:04','2026-07-08 18:48:04','',356,'https://overtakefan.s2-tastewp.com/?p=357',0,'revision','',0),(358,1,'2026-07-08 18:48:42','2026-07-08 18:48:42','<!-- wp:paragraph -->\n<p>[wpforms id=\"339\"]</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Adoption Form','','inherit','closed','closed','','356-revision-v1','','','2026-07-08 18:48:42','2026-07-08 18:48:42','',356,'https://overtakefan.s2-tastewp.com/?p=358',0,'revision','',0),(359,1,'2026-07-08 18:48:49','2026-07-08 18:48:49','<!-- wp:paragraph -->\n<p>[wpforms id=\"339\"]</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Adoption Form','','inherit','closed','closed','','356-revision-v1','','','2026-07-08 18:48:49','2026-07-08 18:48:49','',356,'https://overtakefan.s2-tastewp.com/?p=359',0,'revision','',0),(360,1,'2026-07-08 19:12:36','2026-07-08 19:12:36','<!-- wp:paragraph -->\n<p>[wpforms id=\"339\"]</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Adoption Form','','inherit','closed','closed','','356-revision-v1','','','2026-07-08 19:12:36','2026-07-08 19:12:36','',356,'https://overtakefan.s2-tastewp.com/?p=360',0,'revision','',0),(362,1,'2026-07-08 19:16:17','2026-07-08 19:16:17','<!-- wp:list {\"ordered\":true,\"anchor\":\"gform_fields_1\"} -->\n<ol id=\"gform_fields_1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Complete and submit the online Adoption Information Form</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>ARCH will assess your request and following approval will draw up an adoption contract, prepare travel documents and make transport arrangements</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>The adopter pays transport upfront and the non-refundable adoption fee in full</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Transport of the adopted animal</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>ARCH arranges change of ownership if applicable</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Periodic follow up process through ARCH</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Once we receive your application we will contact you as soon as we have a suitable match for you.The whole process can take anything from a few weeks to various months depending on paperwork and individual circumstances.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>[wpforms id=\"339\"]</p>\n<!-- /wp:paragraph -->','Adoption Form','','inherit','closed','closed','','356-revision-v1','','','2026-07-08 19:16:17','2026-07-08 19:16:17','',356,'https://overtakefan.s2-tastewp.com/?p=362',0,'revision','',0),(364,1,'2026-07-08 19:19:30','2026-07-08 19:19:30','<!-- wp:list {\"ordered\":true,\"anchor\":\"gform_fields_1\"} -->\n<ol id=\"gform_fields_1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li>After you submit the online Adoption Information Form below ARCH will assess your request</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>If your request is approved, we will draw up an adoption contract, prepare travel documents and arrange transport</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>You’ll need to pay transport costs upfront and the non-refundable adoption fee in full before the animal is transported</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>ARCH arranges change of ownership if applicable</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>We’ll follow up with you periodically to find out how you are getting on</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>The whole process can take anything from a few weeks to various months depending on paperwork and individual circumstances.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>[wpforms id=\"339\"]</p>\n<!-- /wp:paragraph -->','Adoption Form','','inherit','closed','closed','','356-revision-v1','','','2026-07-08 19:19:30','2026-07-08 19:19:30','',356,'https://overtakefan.s2-tastewp.com/?p=364',0,'revision','',0),(365,1,'2026-07-08 19:19:47','2026-07-08 19:19:47','<!-- wp:list {\"ordered\":true,\"anchor\":\"gform_fields_1\"} -->\n<ol id=\"gform_fields_1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li>After you submit the for below ARCH will assess your request</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>If your request is approved, we will draw up an adoption contract, prepare travel documents and arrange transport</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>You’ll need to pay transport costs upfront and the non-refundable adoption fee in full before the animal is transported</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>ARCH arranges change of ownership if applicable</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>We’ll follow up with you periodically to find out how you are getting on</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>The whole process can take anything from a few weeks to various months depending on paperwork and individual circumstances.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>[wpforms id=\"339\"]</p>\n<!-- /wp:paragraph -->','Adoption Form','','inherit','closed','closed','','356-revision-v1','','','2026-07-08 19:19:47','2026-07-08 19:19:47','',356,'https://overtakefan.s2-tastewp.com/?p=365',0,'revision','',0),(366,1,'2026-07-08 19:23:12','2026-07-08 19:23:12','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Give one of our equines a home</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>At our rescue centre just outside Málaga, we try to rehome every rescue once they\'re suitably rehabilitated.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Adoption','','inherit','closed','closed','','68-revision-v1','','','2026-07-08 19:23:12','2026-07-08 19:23:12','',68,'https://overtakefan.s2-tastewp.com/?p=366',0,'revision','',0),(368,1,'2026-07-08 19:36:40','2026-07-08 19:36:40','<!-- wp:paragraph -->\n<p>[wpforms id=\"339\"]</p>\n<!-- /wp:paragraph -->','Adoption Form','','inherit','closed','closed','','356-revision-v1','','','2026-07-08 19:36:40','2026-07-08 19:36:40','',356,'https://overtakefan.s2-tastewp.com/?p=368',0,'revision','',0),(371,1,'2026-07-08 19:49:04','2026-07-08 19:49:04','<!-- wp:paragraph -->\n<p>At our rescue centre just outside Málaga, we try to rehome every rescue once they\'re suitably rehabilitated.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Adoption','','inherit','closed','closed','','68-revision-v1','','','2026-07-08 19:49:04','2026-07-08 19:49:04','',68,'https://overtakefan.s2-tastewp.com/?p=371',0,'revision','',0),(376,1,'2026-07-08 20:31:34','2026-07-08 20:31:34','{\n    \"site_icon\": {\n        \"value\": 375,\n        \"type\": \"option\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-07-08 20:31:34\"\n    }\n}','','','trash','closed','closed','','13c7492d-bb1b-455f-88e4-1ce7eacfcb92','','','2026-07-08 20:31:34','2026-07-08 20:31:34','',0,'https://overtakefan.s2-tastewp.com/2026/07/08/13c7492d-bb1b-455f-88e4-1ce7eacfcb92/',0,'customize_changeset','',0),(377,1,'2026-07-08 20:34:29','2026-07-08 20:34:29','{\n    \"blogdescription\": {\n        \"value\": \"Every horse, pony & donkey deserves a happily ever after.\",\n        \"type\": \"option\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-07-08 20:33:59\"\n    },\n    \"site_icon\": {\n        \"value\": 379,\n        \"type\": \"option\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-07-08 20:34:29\"\n    }\n}','','','trash','closed','closed','','64855429-29c4-440a-9e55-d93d195b6022','','','2026-07-08 20:34:29','2026-07-08 20:34:29','',0,'https://overtakefan.s2-tastewp.com/?p=377',0,'customize_changeset','',0),(378,1,'2026-07-08 20:34:16','2026-07-08 20:34:16','','favicon-512','','inherit','open','closed','','favicon-512-2','','','2026-07-08 20:34:16','2026-07-08 20:34:16','',0,'https://overtakefan.s2-tastewp.com/wp-content/uploads/2026/07/favicon-512-1.png',0,'attachment','image/png',0),(379,1,'2026-07-08 20:34:26','2026-07-08 20:34:26','https://overtakefan.s2-tastewp.com/wp-content/uploads/2026/07/cropped-favicon-512-1.png','favicon-512','','inherit','open','closed','','favicon-512','','','2026-07-08 20:34:26','2026-07-08 20:34:26','',378,'https://overtakefan.s2-tastewp.com/wp-content/uploads/2026/07/cropped-favicon-512-1.png',0,'attachment','image/png',0),(381,1,'2026-07-09 20:06:16','2026-07-09 20:06:16','<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">In accordance with regulation (EU) 2016/679 of the European Parliament and of the Council of 27 April 2016</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Effective Date:</strong>&nbsp;27 May 2026</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">1. Introduction</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>This Privacy Policy explains how Andalucian Rescue Centre for Horses (ARCH) (“ARCH”, “we”, “our”, or “us”) collects, uses, stores, and protects your personal information when you visit our website www.horserescuespain.org, contact us, donate, volunteer, adopt an equine, or otherwise interact with our services.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We are committed to protecting your privacy and handling your personal data transparently and in accordance with the European Union General Data Protection Regulation (GDPR) and applicable Spanish data protection laws.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. Who We Are</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>ARCH (Centro Andalusí de Rescate de Caballos) is a registered non-profit organisation dedicated to rescuing, rehabilitating, and rehoming abandoned, abused, and neglected horses, ponies, and donkeys in Andalucía, Spain.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Contact Information</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Organisation:</strong>&nbsp;Centro Andalusí de Rescate de Caballos (ARCH)<br><strong>Represented by::</strong>&nbsp;Jill Newman-Rogers (President)<br><strong>Website:</strong>&nbsp;https://www.horserescuespain.org<br><strong>Email:</strong>&nbsp;<a href=\"mailto:info@horserescuespain.org\">info@horserescuespain.org</a><br><strong>Telephone:</strong>&nbsp;+34 711 070 099<br><strong>Location:</strong>&nbsp;Alhaurín el Grande, Málaga, Spain<br><strong>Spanish Tax ID (CIF):</strong>&nbsp;G92984368</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. What Information We Collect</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We may collect and process the following categories of personal information:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Information You Provide Directly</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Name</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Email address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Telephone number</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Postal address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Donation details</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Volunteer information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Adoption application details</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Messages submitted through contact forms</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Newsletter subscription information</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Sensitive or Additional Information</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>In adoption or volunteer applications, we may collect additional information relevant to assessing suitability, such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Equine ownership experience</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Residency information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Identification or legal residency details where required</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Home check consent information</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Automatically Collected Information</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>When you use our website, we may automatically collect:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>IP address</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Browser type and device information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Pages visited</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cookies and analytics data</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Website usage statistics</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">4. How We Use Your Information</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We use your information to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Respond to enquiries</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Process donations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Manage volunteer applications</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Process equine adoption requests</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Send newsletters and updates</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Improve our website and services</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Organise events and fundraising activities</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Comply with legal obligations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Protect the welfare of animals and support welfare investigations</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>We only process your data where we have a lawful basis to do so under GDPR, including consent, contractual necessity, legal obligation, or legitimate interest.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">5. Reporting Animal Welfare Concerns</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you report a neglected, abandoned, or mistreated equine, we may collect:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Your contact details</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Photographs or evidence</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Location information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Details relating to the welfare concern</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>This information may be shared with relevant authorities such as SEPRONA, local police, veterinarians, or legal representatives where necessary to investigate animal welfare concerns.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">6. Donations and Payments</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you make a donation, payment information may be processed securely by third-party payment providers. ARCH does not store full payment card details on its servers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Please review the privacy policies of any third-party payment processors before submitting payment information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">7. Newsletter Communications</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you subscribe to our newsletter, we may send updates about:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Rescue activities</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Events</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Fundraising campaigns</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Volunteer opportunities</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Equines available for adoption</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>You can unsubscribe at any time by clicking the unsubscribe link in any email or by contacting us directly. (<a href=\"https://www.horserescuespain.org/?utm_source=chatgpt.com\">horserescuespain.org</a>)</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">8. Cookies</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Our website may use cookies and similar technologies to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Improve website functionality</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Analyse traffic and usage</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Remember user preferences</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>You can control cookies through your browser settings. Disabling cookies may affect website functionality.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>This site is protected by <a href=\"https://www.hCaptcha.com\">hCaptcha</a>. Its <a href=\"https://www.hcaptcha.com/privacy\">Privacy Policy</a> and <a href=\"https://www.hcaptcha.com/terms\">Terms of Service</a> apply except as noted in our <a href=\"https://overtakefan.s2-tastewp.com/privacy-policy/\" data-type=\"page\" data-id=\"300\">Privacy Policy</a>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">9. Sharing Your Information</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We do not sell your personal information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We may share your data with:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Veterinary professionals</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Law enforcement or animal welfare authorities</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Payment processors</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Email newsletter providers</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Website hosting and technical service providers</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Legal advisers where necessary</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>All third parties are expected to handle your information securely and lawfully.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">10. Data Retention</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We retain personal information only as long as necessary for:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>The purposes outlined in this policy</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Legal, accounting, or regulatory obligations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Managing ongoing volunteer, adoption, or donation relationships</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>When data is no longer required, it will be securely deleted or anonymised.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">11. Your Rights Under GDPR</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>You have the right to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Access your personal data</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Correct inaccurate information</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Request deletion of your data</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Restrict or object to processing</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Withdraw consent at any time</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Request data portability</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Lodge a complaint with a supervisory authority</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>To exercise any of these rights, please contact us at&nbsp;<a href=\"mailto:info@horserescuespain.org\">info@horserescuespain.org</a>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">12. Data Security</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We take reasonable technical and organisational measures to protect your personal data against:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Unauthorised access</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Loss</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Misuse</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Disclosure</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Alteration or destruction</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>However, no internet transmission or storage system can be guaranteed completely secure.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">13. Third-Party Links</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Our website may contain links to external websites, including social media pages, fundraising platforms, and partner organisations. We are not responsible for the privacy practices or content of external websites.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">14. Children’s Privacy</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Our website and services are not directed toward children under 16 years of age. We do not knowingly collect personal information from children without appropriate parental consent.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">15. Changes to This Privacy Policy</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We may update this Privacy Policy periodically to reflect operational, legal, or regulatory changes. Updated versions will be posted on this page with a revised effective date.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">16. Contact Us</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you have questions about this Privacy Policy or how your personal information is handled, please contact:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>ARCH – Centro Andalusí de Rescate de Caballos</strong><br>Email:&nbsp;<a href=\"mailto:info@horserescuespain.org\">info@horserescuespain.org</a><br>Website:&nbsp;<a href=\"https://www.horserescuespain.org/?utm_source=chatgpt.com\">www.horserescuespain.org</a><br>Location: Alhaurín el Grande, Málaga, Spain (<a href=\"https://www.horserescuespain.org/?utm_source=chatgpt.com\">horserescuespain.org</a>)</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Privacy Policy','','inherit','closed','closed','','300-revision-v1','','','2026-07-09 20:06:16','2026-07-09 20:06:16','',300,'https://overtakefan.s2-tastewp.com/?p=381',0,'revision','',0),(382,1,'2026-07-09 20:42:26','0000-00-00 00:00:00','','Auto Draft','','auto-draft','open','open','','','','','2026-07-09 20:42:26','0000-00-00 00:00:00','',0,'https://overtakefan.s2-tastewp.com/?p=382',0,'post','',0),(384,1,'2026-07-10 17:49:50','2026-07-10 17:49:50','','Donation Thank You','','publish','closed','closed','','donation-thank-you','','','2026-07-10 17:49:50','2026-07-10 17:49:50','',0,'https://overtakefan.s2-tastewp.com/?page_id=384',0,'page','',0),(385,1,'2026-07-10 17:49:50','2026-07-10 17:49:50','','Donation Thank You','','inherit','closed','closed','','384-revision-v1','','','2026-07-10 17:49:50','2026-07-10 17:49:50','',384,'https://overtakefan.s2-tastewp.com/?p=385',0,'revision','',0),(386,1,'2026-07-10 17:54:39','0000-00-00 00:00:00','','Auto Draft','','auto-draft','closed','closed','','','','','2026-07-10 17:54:39','0000-00-00 00:00:00','',0,'https://overtakefan.s2-tastewp.com/?post_type=equine&p=386',0,'equine','',0),(388,1,'2026-07-10 18:05:33','2026-07-10 18:05:33','','Pexels','','publish','closed','closed','','pexels','','','2026-07-10 18:12:05','2026-07-10 18:12:05','',0,'https://overtakefan.s2-tastewp.com/?post_type=equine&#038;p=388',0,'equine','',0),(389,1,'2026-07-10 18:04:02','2026-07-10 18:04:02','','pexels','','inherit','open','closed','','pexels','','','2026-07-10 18:04:02','2026-07-10 18:04:02','',388,'https://overtakefan.s2-tastewp.com/wp-content/uploads/2026/07/pexels.jpeg',0,'attachment','image/jpeg',0),(390,1,'2026-07-10 18:06:04','2026-07-10 18:06:04','','In Loving Memory 🕯️','','publish','closed','closed','','loving-memory','','','2026-07-10 18:17:42','2026-07-10 18:17:42','',0,'https://overtakefan.s2-tastewp.com/?page_id=390',